mapper.select:
SELECT * FROM ( SELECT n.notice_code AS noticeCode, n.project_code AS projectCode, p.project_name AS projectName, n.title AS title, n.created_at AS createdAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN notices n ON n.project_code = p.project_code
WHERE p.status = 'OD1' ORDER BY n.created_at DESC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT i.issue_code AS issueCode, i.title AS title, cs.code_name AS statusName, cp.code_name AS priorityName, i.due_at AS dueAt FROM issues i JOIN status s ON s.status_code = i.status_code LEFT JOIN common_code cs ON cs.code_id = s.code_id LEFT JOIN common_code cp ON cp.code_id = i.priority WHERE i.project_code = #{projectCode}
-- ✅ 관리자인 경우: 클릭한 assigneeCode로 필터(비어있으면 전체) -- ✅ 비관리자인 경우: 무조건 자기(userCode)만 보이게 강제 AND ( (#{isAdmin} = 'Y' AND (#{assigneeCode} IS NULL OR i.assignee_code = #{assigneeCode})) OR (#{isAdmin} != 'Y' AND i.assignee_code = #{userCode}) )
-- 상태 필터(비어있으면 전체) AND (#{statusId} IS NULL OR #{statusId} = '' OR s.code_id = #{statusId})
ORDER BY i.due_at NULLS LAST, NVL(i.updated_at, i.created_at) DESC ) WHERE ROWNUM <= #{limit}

SELECT p.project_name
FROM projects p
WHERE p.project_code = #{projectCode}

